<?php
$pageTitle='Tenant Onboarding';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('tenant_onboarding');
$pdo=getDB();$companies=$pdo->query('SELECT id,company_code,company_name FROM '.table('companies').' WHERE status="active" ORDER BY company_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'task');
    if($action==='domain'){$number=nextScopedDocumentNumber($pdo,'tenant_domain',setting('tenant_domain_prefix','DOM'),operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('saas_tenant_domains').' (domain_number,company_id,domain_name,is_primary,status,created_by) VALUES (?,?,?,?,?,?)')->execute([$number,(int)$_POST['company_id'],trim((string)$_POST['domain_name']),(int)($_POST['is_primary']??0),trim((string)$_POST['status']),(int)(currentUser()['id']??0)?:null]);flash('success','Tenant domain added.');}
    elseif($action==='complete'){$pdo->prepare('UPDATE '.table('saas_onboarding_tasks').' SET status="completed",completed_at=NOW() WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Onboarding task completed.');}
    else{createTenantOnboardingTask($pdo,(int)$_POST['company_id'],trim((string)$_POST['task_title']),trim((string)$_POST['task_type']),trim((string)$_POST['due_date']),(int)($_POST['assigned_to']??0)?:null,trim((string)$_POST['notes']));flash('success','Onboarding task created.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'tenant-onboarding']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/tenant-onboarding.php');
}
$tasks=$pdo->query('SELECT t.*,c.company_name,u.email assigned_email FROM '.table('saas_onboarding_tasks').' t LEFT JOIN '.table('companies').' c ON c.id=t.company_id LEFT JOIN '.table('users').' u ON u.id=t.assigned_to ORDER BY FIELD(t.status,"pending","completed"),t.due_date ASC,t.created_at DESC LIMIT 200')->fetchAll();
$domains=$pdo->query('SELECT d.*,c.company_name FROM '.table('saas_tenant_domains').' d LEFT JOIN '.table('companies').' c ON c.id=d.company_id ORDER BY d.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Tenant Go-Live Control</div><h2 class="h4 mb-1">Tenant Onboarding</h2><p class="text-secondary mb-0">Track setup tasks, domains, verification and go-live readiness.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Task</h2><select class="form-select mb-2" name="company_id"><?php foreach($companies as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['company_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="task_title" placeholder="Connect domain / import products"><select class="form-select mb-2" name="task_type"><option>setup</option><option>training</option><option>billing</option><option>domain</option><option>data_import</option></select><input class="form-control mb-2" type="date" name="due_date"><input class="form-control mb-2" type="number" name="assigned_to" placeholder="Assigned user ID"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Task</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="domain"><h2 class="h5 mb-3">Add Domain</h2><select class="form-select mb-2" name="company_id"><?php foreach($companies as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['company_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="domain_name" placeholder="client.example.com"><select class="form-select mb-2" name="is_primary"><option value="0">Secondary</option><option value="1">Primary</option></select><select class="form-select mb-3" name="status"><option>pending</option><option>verified</option><option>failed</option></select><button class="btn btn-outline-primary w-100">Add Domain</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Onboarding Tasks</h2><table class="table"><thead><tr><th>Task</th><th>Tenant</th><th>Due</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($tasks as $t): ?><tr><td><strong><?php echo esc($t['task_number']); ?></strong><div class="small text-secondary"><?php echo esc($t['task_title'].' · '.$t['task_type']); ?></div></td><td><?php echo esc($t['company_name']); ?></td><td><?php echo esc($t['due_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($t['status'])); ?>"><?php echo esc($t['status']); ?></span></td><td><?php if($t['status']!=='completed'): ?><form method="post"><input type="hidden" name="action" value="complete"><input type="hidden" name="id" value="<?php echo (int)$t['id']; ?>"><button class="btn btn-sm btn-success">Complete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Tenant Domains</h2><table class="table"><thead><tr><th>Domain</th><th>Tenant</th><th>Primary</th><th>Status</th></tr></thead><tbody><?php foreach($domains as $d): ?><tr><td><strong><?php echo esc($d['domain_number']); ?></strong><div class="small text-secondary"><?php echo esc($d['domain_name']); ?></div></td><td><?php echo esc($d['company_name']); ?></td><td><?php echo $d['is_primary']?'Yes':'No'; ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>